import * as anchor from "@coral-xyz/anchor";
import type { Idl, Wallet, Program as AnchorProgram } from "@coral-xyz/anchor";
import {
  Connection,
  Keypair,
  PublicKey,
  ComputeBudgetProgram,
} from "@solana/web3.js";
import { DEVNET_PROGRAM_ID } from "./constants.js";
import { fetchBeacon, getCurrentRound } from "./drand.js";
import { getConfigAddress } from "./instruction.js";
import { AleaError, ERRORS } from "./errors.js";
import { IDL } from "./idl.js";

// Phase 4.5 T1-01: IDL inlined as a TS const (see src/idl.ts, generated by
// scripts/generate-idl-ts.mjs). Eliminates all fs/url/path imports so
// @alea-drand/sdk runs in any browser bundler (Vite, webpack, Next.js App Router,
// esbuild) with no polyfills. Previous readFileSync approach worked in Node
// but broke any SSR or client-only build.
const idl: Idl = IDL;

const U64_MAX = 18_446_744_073_709_551_615n; // 2^64 - 1

// Phase 4.5 T1-05: isBrowserWallet with null/undefined guard. Previous
// `"sendTransaction" in signer` threw `TypeError` on null because `in` is
// not null-safe. Now any falsy signer returns false (→ downstream null
// check in verifyDrandBeacon throws AleaError 6102 with a readable message).
function isBrowserWallet(signer: Keypair | Wallet | null | undefined): signer is Wallet {
  return (
    signer !== null &&
    signer !== undefined &&
    typeof signer === "object" &&
    "sendTransaction" in signer &&
    typeof (signer as { sendTransaction?: unknown }).sendTransaction === "function"
  );
}

function sleep(ms: number): Promise<void> {
  return new Promise((r) => setTimeout(r, ms));
}

// Extract an on-chain Solana custom-program error code from any of the error
// shapes thrown by web3.js / Anchor under skipPreflight=true. Mirrors the
// errCode() helper in scripts/devnet-verify-loop.ts. Returns undefined if no
// recognizable code is present.
function extractErrorCode(err: unknown): number | undefined {
  if (!err || typeof err !== "object") return undefined;
  const e = err as Record<string, any>;

  // Anchor-wrapped error
  const anchorCode =
    e["error"]?.errorCode?.number ??
    e["errorCode"]?.number ??
    (typeof e["code"] === "number" ? e["code"] : undefined);
  if (typeof anchorCode === "number") return anchorCode;

  // Raw Solana {InstructionError: [ixIdx, {Custom: N}]}
  const ie = e["InstructionError"];
  if (Array.isArray(ie) && ie.length === 2) {
    const inner = ie[1];
    if (inner && typeof inner.Custom === "number") return inner.Custom;
  }

  // web3.js SendTransactionError: logs are under either `logs` or `transactionLogs`
  const logs: string[] | undefined =
    (Array.isArray(e["logs"]) && e["logs"]) ||
    (Array.isArray(e["transactionLogs"]) && e["transactionLogs"]) ||
    undefined;
  if (logs) {
    for (const line of logs) {
      const mA = String(line).match(/Error Number: (\d+)/);
      if (mA && mA[1]) return parseInt(mA[1], 10);
      const mB = String(line).match(/custom program error: 0x([0-9a-fA-F]+)/);
      if (mB && mB[1]) return parseInt(mB[1], 16);
    }
  }

  return undefined;
}

/**
 * Tx metadata returned alongside the verified randomness. Populated from
 * `getTransaction().meta` after `confirmed` commitment. Useful for
 * consumers that need to link to Explorer, report CU usage, or compute
 * per-call cost (e.g., the alea.so public relayer).
 */
export type VerifyMeta = {
  /** 32-byte verified randomness from the program's return data. */
  randomness: Uint8Array;
  /** Base58 Solana tx signature. Suitable for Explorer URLs. */
  tx: string;
  /** Slot the tx confirmed in. */
  slot: number;
  /** CU consumed per `meta.computeUnitsConsumed`. 0 if unavailable. */
  computeUnitsUsed: number;
  /** Fee paid in lamports per `meta.fee`. 0 if unavailable. */
  costLamports: number;
};

/**
 * Verify a drand beacon on-chain AND return the tx metadata (sig, slot,
 * CU, fee) alongside the randomness. Use when you need more than just
 * the 32-byte randomness — e.g., to show the verification tx on
 * Explorer, or to report compute/cost to end users.
 *
 * Same signature as `verifyDrandBeacon`; only the return shape differs.
 * Added in 0.2.0 for the alea.so relayer use case.
 */
export async function verifyDrandBeaconWithMeta(args: {
  connection: Connection;
  signer: Keypair | Wallet;
  round: bigint;
  signature: Uint8Array;
  programId?: PublicKey;
  computeUnits?: number;
  /**
   * Abort signal — when aborted BEFORE the tx is sent, the call throws
   * AleaError 6103 and no tx lands on-chain. Once sent, the abort is a
   * no-op (we can't un-send a Solana tx). Use for navigation-away and
   * UI timeout patterns.
   */
  signal?: AbortSignal;
  /**
   * Override the default `skipPreflight: true`. Setting this to `false`
   * enables Solana preflight simulation — useful for debugging an
   * integration locally, but likely to fail under live devnet/mainnet
   * load because Alea's pairing CU can outpace the preflight blockhash
   * window. Default stays `true`.
   */
  skipPreflight?: boolean;
}): Promise<VerifyMeta> {
  // Phase 4.5 input validation (T1-04, T1-05, T1-06): defensive checks at
  // the SDK boundary so consumers get readable AleaError instead of opaque
  // Node/web3.js failures downstream.
  if (!args.signer) {
    throw new AleaError(
      6102,
      `InvalidInput: signer is required (got ${args.signer === null ? "null" : "undefined"})`,
    );
  }
  if (typeof args.round !== "bigint") {
    throw new AleaError(
      6102,
      `InvalidInput: round must be bigint (got ${typeof args.round})`,
    );
  }
  if (args.round < 1n || args.round > U64_MAX) {
    throw new AleaError(
      6102,
      `InvalidInput: round must be in [1, 2^64-1] (got ${args.round.toString()})`,
    );
  }
  if (!(args.signature instanceof Uint8Array)) {
    throw new AleaError(
      6102,
      "InvalidInput: signature must be a Uint8Array",
    );
  }
  if (args.signature.length !== 64) {
    throw new AleaError(
      6102,
      `InvalidInput: signature must be exactly 64 bytes (G1 uncompressed x||y); got ${args.signature.length}`,
    );
  }

  const wallet: Wallet = isBrowserWallet(args.signer)
    ? args.signer
    : new anchor.Wallet(args.signer as Keypair);

  const provider = new anchor.AnchorProvider(args.connection, wallet, {
    commitment: "confirmed",
  });

  const programId = args.programId ?? DEVNET_PROGRAM_ID;

  // Anchor 0.30 Program constructor: (idl, provider?, coder?)
  // The IDL embeds the address — override programId via the provider approach
  // by patching the IDL address field if different from devnet.
  let effectiveIdl = idl;
  if (programId.toBase58() !== (idl as any).address) {
    effectiveIdl = { ...idl, address: programId.toBase58() } as Idl;
  }
  const program = new anchor.Program(effectiveIdl, provider) as AnchorProgram<Idl>;

  const configPda = getConfigAddress(programId);

  const cuLimit = args.computeUnits ?? 900_000;
  const cuIx = ComputeBudgetProgram.setComputeUnitLimit({ units: cuLimit });

  // Build the transaction via Anchor's IDL (discriminator + arg serialization)
  // but SEND it ourselves via connection.sendRawTransaction. This bypasses
  // Anchor 0.30.1's `.rpc()` error-wrapping path, which is broken against
  // @solana/web3.js ≥ 1.98: Anchor calls `new SendTransactionError(msg, logs)`
  // (old 2-arg positional signature) but web3.js 1.98 changed the constructor
  // to object destructuring `{action, signature, transactionMessage, logs}`.
  // The result is a thrown Error with message "Unknown action 'undefined'"
  // and all properties undefined — losing all error-code information.
  //
  // By building the tx + signing + sending ourselves, we read the on-chain
  // failure cleanly from `getTransaction().meta.err` (raw Solana
  // `{InstructionError: [ixIdx, {Custom: N}]}` shape) and map to AleaError.
  // T1.09: BN accepts string for bigint safety.
  const anchorTx: anchor.web3.Transaction = await (program.methods as any)
    .verify(new anchor.BN(args.round.toString()), Array.from(args.signature))
    .accounts({ config: configPda, payer: wallet.publicKey })
    .preInstructions([cuIx])
    .transaction();

  // Phase 4.5 T2-15: early-abort check before any network calls. Throws
  // AleaError 6103 if the user's AbortSignal is already aborted (e.g.,
  // they navigated away before we started).
  if (args.signal?.aborted) {
    throw new AleaError(6103, "verifyDrandBeacon aborted by caller");
  }

  // Phase 4.5 T2-16: verify the wallet actually exposes signTransaction
  // before we lean on it. Hardware and watch-only wallets can expose a
  // partial WalletContextState where signTransaction is undefined,
  // producing an opaque TypeError below.
  if (typeof wallet.signTransaction !== "function") {
    throw new AleaError(
      6102,
      "InvalidInput: signer.signTransaction is not a function — ensure wallet is connected and supports signing (watch-only / hardware wallets without signTransaction are not supported)",
    );
  }

  const { blockhash, lastValidBlockHeight } = await args.connection.getLatestBlockhash("confirmed");
  anchorTx.recentBlockhash = blockhash;
  anchorTx.feePayer = wallet.publicKey;
  const signedTx = await wallet.signTransaction(anchorTx);

  // Phase 4.5 T2-15: second abort checkpoint after signing. Still
  // recoverable because the tx hasn't been broadcast yet. Once we send,
  // aborts are a no-op.
  if (args.signal?.aborted) {
    throw new AleaError(6103, "verifyDrandBeacon aborted by caller after signing (tx NOT sent)");
  }

  // Phase 4.5 T2-17: skipPreflight defaults to true (required for live
  // devnet/mainnet CU envelope), but consumers can override for local
  // debugging.
  const skipPreflight = args.skipPreflight ?? true;
  const tx: string = await args.connection.sendRawTransaction(
    signedTx.serialize(),
    { skipPreflight, maxRetries: 3 },
  );

  // Wait for confirmation. Don't use confirmTransaction's promise because on
  // failure it throws with a similarly-broken shape; instead, poll
  // getTransaction until it returns (confirmed commitment) and then inspect
  // meta.err ourselves.
  await args.connection.confirmTransaction(
    { signature: tx, blockhash, lastValidBlockHeight },
    "confirmed",
  ).catch(() => {
    // confirmTransaction rejects on on-chain failure — we'll read meta.err
    // from the polled getTransaction below. Swallow here to unify the error
    // path through the meta.err extraction logic.
  });

  // Retry getTransaction — Helius indexer lags 2-5s post-send per
  // [[2026-04-18-helius-devnet-indexer-lag]].
  let info = null;
  for (let attempt = 0; attempt < 15; attempt++) {
    info = await args.connection.getTransaction(tx, {
      commitment: "confirmed",
      maxSupportedTransactionVersion: 0,
    });
    if (info) break;
    await sleep(1000);
  }

  if (!info) {
    throw new AleaError(
      6009,
      `ReturnDataMissing: getTransaction returned null for sig ${tx}`,
    );
  }
  if (info.meta?.err) {
    // Raw Solana {InstructionError: [ixIdx, {Custom: N}]} — extract and map.
    const raw = info.meta.err as any;
    const ie = raw?.InstructionError;
    if (Array.isArray(ie) && ie.length === 2) {
      const inner = ie[1] as any;
      if (typeof inner?.Custom === "number") {
        const code: number = inner.Custom;
        const msg = ERRORS[code] ?? `Unknown error code ${code}`;
        throw new AleaError(code, msg);
      }
    }
    // Fall back to log-scan for "Error Number: N" patterns.
    const code = extractErrorCode({ logs: info.meta.logMessages });
    if (typeof code === "number") {
      throw new AleaError(code, ERRORS[code] ?? `Unknown error code ${code}`);
    }
    throw new Error(`Transaction failed on-chain: ${JSON.stringify(raw)}`);
  }

  // T2.03 — extract return data (32-byte randomness) from tx metadata
  const returnData = (info.meta as any)?.returnData;
  if (!returnData?.data) {
    throw new AleaError(
      6009,
      "ReturnDataMissing: verify succeeded but return data absent",
    );
  }

  const [dataB64] = returnData.data as [string, string];
  const decoded = Buffer.from(dataB64, "base64");
  if (decoded.length < 32) {
    throw new AleaError(
      6009,
      `ReturnDataMissing: expected 32 bytes, got ${decoded.length}`,
    );
  }

  return {
    randomness: new Uint8Array(decoded.subarray(0, 32)),
    tx,
    slot: info.slot,
    computeUnitsUsed: info.meta?.computeUnitsConsumed ?? 0,
    costLamports: info.meta?.fee ?? 0,
  };
}

/**
 * Verify a drand beacon on-chain. Returns just the 32-byte randomness.
 * Thin wrapper over `verifyDrandBeaconWithMeta` — use that variant if
 * you also need the tx signature, slot, CU usage, or fee.
 */
export async function verifyDrandBeacon(args: {
  connection: Connection;
  signer: Keypair | Wallet;
  round: bigint;
  signature: Uint8Array;
  programId?: PublicKey;
  computeUnits?: number;
  signal?: AbortSignal;
  skipPreflight?: boolean;
}): Promise<Uint8Array> {
  const meta = await verifyDrandBeaconWithMeta(args);
  return meta.randomness;
}

export async function getVerifiedRandomness(options: {
  connection: Connection;
  signer: Keypair | Wallet;
  programId?: PublicKey;
  round?: bigint;
  computeUnits?: number;
  /** Abort signal threaded through fetchBeacon + verifyDrandBeacon. */
  signal?: AbortSignal;
  /** See verifyDrandBeacon.skipPreflight. Default true. */
  skipPreflight?: boolean;
}): Promise<Uint8Array> {
  const round = options.round ?? getCurrentRound();
  const beacon = await fetchBeacon(round, { signal: options.signal });

  return verifyDrandBeacon({
    connection: options.connection,
    signer: options.signer,
    round: beacon.round,
    signature: beacon.signature,
    programId: options.programId,
    computeUnits: options.computeUnits,
    signal: options.signal,
    skipPreflight: options.skipPreflight,
  });
}

/**
 * Fetch the current (or specified) drand round AND verify it on-chain
 * in a single call, returning the full proof record: round + drand
 * signature + randomness + tx + slot + CU + fee. Use for consumers
 * like the alea.so public relayer that need all fields in one shot.
 *
 * Added in 0.2.0.
 */
export async function getVerifiedRandomnessWithMeta(options: {
  connection: Connection;
  signer: Keypair | Wallet;
  programId?: PublicKey;
  round?: bigint;
  computeUnits?: number;
  signal?: AbortSignal;
  skipPreflight?: boolean;
}): Promise<VerifyMeta & { round: bigint; signature: Uint8Array }> {
  const round = options.round ?? getCurrentRound();
  const beacon = await fetchBeacon(round, { signal: options.signal });

  const meta = await verifyDrandBeaconWithMeta({
    connection: options.connection,
    signer: options.signer,
    round: beacon.round,
    signature: beacon.signature,
    programId: options.programId,
    computeUnits: options.computeUnits,
    signal: options.signal,
    skipPreflight: options.skipPreflight,
  });

  return {
    ...meta,
    round: beacon.round,
    signature: beacon.signature,
  };
}
